const makeCard = (id, question, subcategory, answer, firm = "Moody's", difficulty = 'Medium') => ({
  id,
  question,
  category: 'Interview Ready',
  tag: 'archive',
  subcategory,
  firm,
  difficulty,
  answer,
  relatedIds: [],
});

export const interviewReadyArchiveExpansion = [
  makeCard('ir_107', 'What projected information is best used to assess working-capital limits?', 'Written Assessment', 'Use projected financial statements and the working-capital assessment or CMA data: projected sales, production, receivables, inventory, payables, operating-cycle days, and the resulting peak funding requirement. Historic statements validate the assumptions; projections size the facility.'),
  makeCard('ir_110', 'What is one of the three levels of oversight in the corporate-governance process?', 'Written Assessment', 'The three-lines model includes management and operational controls as the first line, risk and compliance oversight as the second line, and independent internal audit as the third line.'),
  makeCard('ir_111', 'What type of risk is the risk that credit exposure is not adequately structured?', 'Written Assessment', 'It is transaction or structuring risk: the facility terms, security package, covenants, tenor, repayment profile, or documentation may not fit the borrower’s cash flows and the lender’s downside protection.'),
  makeCard('ir_112', 'What effect would a decrease in sales growth during a recession have on cash flow?', 'Written Assessment', 'Lower sales growth can reduce operating cash generation and leave fixed costs, inventory, and debt service unchanged. Receivables may collect more slowly and inventory may build, so CFO and free cash flow can fall even before accounting profit turns negative.'),
  makeCard('ir_113', 'Which factor can make it difficult to project financial performance from historic trends?', 'Written Assessment', 'A structural break—such as a recession, regulatory change, new technology, acquisition, loss of a major customer, or change in business model—can make historical relationships unreliable. Forecasts must separate recurring drivers from discontinued conditions.'),
  makeCard('ir_114', 'What is the primary purpose of calculating drawing power in a funds-based working-capital facility?', 'Written Assessment', 'Drawing power limits borrowing to the realizable value of eligible current assets after margins and exclusions. It prevents the borrower from drawing against obsolete inventory, doubtful receivables, or collateral already consumed by other claims.'),
  makeCard('ir_115', 'What is the first step for a management team seeking results through the efforts of others?', 'Written Assessment', 'Set a clear objective and define the outcome, accountability, resources, and decision rights. Delegation works only after the team knows what success means and how progress will be measured.'),
  makeCard('ir_116', 'Which activity can reduce a company’s cash-flow position?', 'Written Assessment', 'A cash use such as purchasing inventory, extending customer credit, paying down debt, acquiring fixed assets, or paying dividends reduces cash. The answer should distinguish operating, investing, and financing cash flows.'),
  makeCard('ir_117', 'What early-warning signal may result from technology changes?', 'Written Assessment', 'Technology disruption can show up as falling margins, obsolete inventory, rising capex, loss of customers, cybersecurity incidents, weaker demand, or a need to refinance investment before the benefits arrive. The signal is not “technology” itself but its effect on cash flow and competitiveness.'),
  makeCard('ir_118', 'What is the primary purpose of the loan pricing process?', 'Written Assessment', 'To price the facility so expected return compensates for funding cost, expected loss, capital usage, operating cost, liquidity, tenor, collateral, and risk-adjusted return requirements.'),
  makeCard('ir_119', 'During which implementation phase of a deal structure is counsel instructed on documentation and covenant-definition issues?', 'Written Assessment', 'Counsel is typically instructed during the documentation or structuring-and-documentation phase, after the commercial terms and credit approval are sufficiently agreed but before closing. Counsel converts the approved risk protections into enforceable documents.'),
  makeCard('ir_120', 'In what type of feasibility assessment is a project’s maximum debt-to-equity ratio reviewed?', 'Written Assessment', 'It is reviewed in the financial feasibility assessment. The analyst tests leverage capacity, debt-service ability, funding sources, projected cash flows, sensitivity cases, and the sponsor’s equity contribution.'),
  makeCard('ir_121', 'How might an inadequate management-succession plan affect a business’s cash flow?', 'Written Assessment', 'Key-person dependence can disrupt customers, suppliers, strategy, controls, and lender confidence. The resulting revenue loss, higher costs, delayed decisions, or refinancing difficulty can weaken operating and financing cash flows.'),
  makeCard('ir_124', 'What is the formula for IRR, and how should you explain it in an interview?', 'Corporate Finance & Valuation', 'IRR is the discount rate r that sets the NPV of all project cash flows to zero: 0 = Σ CFt/(1+r)^t. It is the project’s implied annual return, but it can mislead with non-conventional cash flows, multiple sign changes, scale differences, or reinvestment assumptions.'),
  makeCard('ir_125', 'Define FCFF and differentiate it from FCFE. Why is interest not deducted in FCFF?', 'Corporate Finance & Valuation', 'FCFF is cash flow available to debt and equity providers: EBIT(1−tax rate) + D&A − capex − change in NWC. FCFE is cash flow available to equity after interest, debt issuance, and principal repayment. FCFF is discounted at WACC, so interest is reflected through the capital-provider discount rate rather than deducted from the pre-financing cash flow.'),
  makeCard('ir_126', 'Define Enterprise Value and Market Capitalization. How are they connected?', 'Corporate Finance & Valuation', 'Market capitalization is share price multiplied by diluted shares outstanding. Enterprise Value measures the operating business available to all capital providers: market cap + debt + preferred stock + minority interest − excess cash, with other debt-like items added when relevant.'),
  makeCard('ir_128', 'Explain WACC and how you compute the cost of each capital component.', 'Corporate Finance & Valuation', 'WACC = E/V×cost of equity + D/V×after-tax cost of debt, adjusted for preferred capital where relevant. Cost of equity commonly uses CAPM: risk-free rate + beta×equity risk premium. Cost of debt is the market borrowing yield or credit spread plus the risk-free rate, multiplied by (1−tax rate) when the interest shield is usable.'),
  makeCard('ir_129', 'What are Enterprise Value multiples?', 'Corporate Finance & Valuation', 'EV/Revenue, EV/EBITDA, EV/EBIT, and EV/Invested Capital compare the value of operations with operating or capital-base measures. They are useful only when growth, margins, reinvestment, cyclicality, accounting policies, and capital intensity are comparable.'),
  makeCard('ir_130', 'What is the difference between DCF and relative valuation, and when can each fail?', 'Corporate Finance & Valuation', 'DCF values explicit and terminal free cash flows using a discount rate; relative valuation benchmarks a company against trading or transaction multiples. DCF is sensitive to assumptions, while relative valuation can import sector mispricing or weak comparables. Use both as cross-checks and reconcile the drivers.'),
  makeCard('ir_131', 'What is the Hindenburg report on Adani, and how would a credit analyst discuss it?', 'Structured Finance & Private Credit', 'It was a 2023 short-seller report alleging accounting, governance, ownership, and market-manipulation concerns around Adani Group entities. A credit analyst should separate allegation from verified fact, assess issuer responses and regulatory findings, then test liquidity, refinancing, related-party exposure, collateral value, covenants, and contagion across the group.'),
  makeCard('ir_132', 'Explain calls and puts.', 'Fixed Income & Derivatives', 'A call gives the holder the right, not the obligation, to buy an underlying at the strike before or at expiry; a put gives the right to sell. Buyers pay a premium and have limited loss; sellers receive premium but take potentially large exposure. Calls benefit from upside, puts from downside or protection.'),
  makeCard('ir_133', 'What are the main asset classes in a portfolio?', 'Fixed Income & Derivatives', 'Common classes are equities, fixed income, cash and money-market instruments, real estate, commodities, currencies, and alternatives such as private equity, private credit, hedge funds, and infrastructure. Diversification works only when exposures are economically different, not merely differently named.'),
  makeCard('ir_134', 'What is short selling?', 'Fixed Income & Derivatives', 'An investor borrows an asset and sells it, intending to repurchase it later at a lower price and return it to the lender. Profit is limited to the sale proceeds but loss is theoretically unlimited; borrow cost, margin calls, dividends, recalls, and short squeezes matter.'),
  makeCard('ir_135', 'How do you calculate and interpret break-even point?', 'Corporate Finance & Valuation', 'Break-even units = fixed costs ÷ contribution margin per unit. Break-even revenue = fixed costs ÷ contribution margin ratio. It is the volume at which operating profit is zero; sensitivity to price, mix, variable cost, fixed cost, and capacity determines how useful it is.'),
  makeCard('ir_136', 'How do Beta, WACC, and Debt-to-Equity ratio relate?', 'Corporate Finance & Valuation', 'Beta measures equity sensitivity to market risk and feeds the cost of equity through CAPM. More debt can increase financial leverage and equity beta, while cheaper after-tax debt can lower WACC until financial distress, agency costs, and rising spreads outweigh the tax shield. Use market-value capital weights.'),
  makeCard('ir_137', 'Differentiate primary and secondary markets and explain the financing effect.', 'Corporate Finance & Valuation', 'Primary markets issue new securities and provide capital to the issuer. Secondary markets trade existing securities and provide liquidity and price discovery. Strong secondary liquidity can lower the issuer’s cost of capital, while a weak market can make primary funding expensive or unavailable.'),
  makeCard('ir_138', 'Explain debt versus equity financing and when a firm might prefer each.', 'Corporate Finance & Valuation', 'Debt preserves ownership and may provide a tax shield but creates mandatory payments, covenants, and default risk. Equity has no contractual repayment but dilutes ownership and usually has a higher required return. Choose based on cash-flow stability, leverage capacity, flexibility, valuation, control, and market conditions.'),
  makeCard('ir_141', 'What is the net worth of an individual?', 'Credit & Underwriting', 'Net worth = total assets − total liabilities. For credit analysis, verify ownership, liquidity, encumbrances, valuation haircuts, contingent liabilities, guarantees, tax claims, and whether assets can actually support the proposed obligation.'),
  makeCard('ir_144', 'What KPIs matter most across consumer versus corporate credit pools?', 'Credit & Underwriting', 'Consumer pools emphasize delinquency roll rates, vintage loss curves, prepayment, utilization, FICO or bureau bands, recovery, and concentration. Corporate pools emphasize leverage, interest and DSCR coverage, liquidity, covenant headroom, maturities, customer concentration, collateral, and sponsor support.'),
  makeCard('ir_145', 'Explain RDBMS and why relational design matters in credit analytics.', 'SQL & Excel', 'An RDBMS stores related entities in tables connected by keys and enforces constraints such as uniqueness and referential integrity. In credit analytics, separating borrowers, facilities, payments, collateral, ratings, and covenants reduces duplication and supports reproducible joins, history, controls, and audit trails.'),
  makeCard('ir_146', 'How do you ensure data quality and integrity in your analyses?', 'SQL & Excel', 'Define ownership and validation rules, check completeness, uniqueness, validity, consistency, timeliness, and referential integrity, reconcile totals to source systems, log transformations, version assumptions, investigate exceptions, and retain an audit trail from source to output.'),
  makeCard('ir_147', 'Describe a time when you used SQL to solve a data problem.', 'SQL & Excel', 'Use STAR: state the business question, identify the source tables, explain the joins and filters, validate the output against control totals, and describe the decision it enabled. Mention an actual issue such as duplicate records, late payments, inconsistent identifiers, or a reconciliation break.'),
  makeCard('ir_148', 'What statistical methods do you commonly use in analysis?', 'SQL & Excel', 'Use descriptive statistics, distributions, cohort and vintage analysis, correlation, regression, hypothesis tests, confidence intervals, outlier analysis, and scenario or sensitivity analysis. Match the method to the question and state assumptions, data limitations, and whether correlation is being mistaken for causation.'),
  makeCard('ir_149', 'What are five useful advanced Excel functions beyond SUMIFS and COUNTIFS?', 'SQL & Excel', 'Examples include XLOOKUP, INDEX/MATCH, FILTER, LET, LAMBDA, UNIQUE, SORT, SUMPRODUCT, and dynamic-array combinations. The best answer explains the business use, error handling, auditability, and why a formula is preferable to a hard-coded result.'),
  makeCard('ir_151', 'Name five Excel shortcuts that save time in daily analysis.', 'SQL & Excel', 'Useful examples are Ctrl+Arrow to move through a data region, Ctrl+Shift+Arrow to select it, Ctrl+1 for Format Cells, F4 to repeat or lock a reference, Ctrl+; for today’s date, Alt+= for AutoSum, and Ctrl+PageUp/PageDown to move worksheets.'),
  makeCard('ir_152', 'How do you split data in one cell into different Excel cells?', 'SQL & Excel', 'Use Text to Columns for a one-time delimiter or fixed-width split, TEXTSPLIT for a dynamic Excel 365 model, Flash Fill for a pattern, or Power Query for repeatable transformation. Validate row counts, blanks, delimiters inside quoted text, and data types afterward.'),
  makeCard('ir_154', 'How do you validate a platform report for a new client?', 'SQL & Excel', 'Trace each output to its source field and business rule, test representative positive and negative cases, reconcile record counts and totals, compare edge cases and date cut-offs, obtain client sign-off on definitions, and document defects, fixes, and regression tests.'),
  makeCard('ir_155', 'How do you reconcile discrepancies between source data and platform outputs?', 'SQL & Excel', 'Freeze the inputs and reporting period, compare keys and row counts, isolate differences by field and transformation step, check time zones, rounding, filters, duplicates, missing joins, and stale extracts, then agree the corrected source or rule and retain an exception log.'),
  makeCard('ir_156', 'If a client requests a last-minute change to a financial report, how would you respond?', 'Behavioral & Situational', 'Clarify the requested outcome and deadline, assess materiality and downstream impact, confirm whether evidence supports the change, communicate the trade-off, make the smallest controlled update, rerun key checks, version the file, and obtain approval before release.'),
  makeCard('ir_157', 'What would you do after finding a significant financial-model error just before a deadline?', 'Behavioral & Situational', 'Stop relying on the affected output, quantify the impact, notify the responsible lead immediately, preserve the original version, fix and test the model, communicate what changed and what remains uncertain, and release only after an independent review or explicit risk acceptance.'),
  makeCard('ir_158', 'How would you handle conflicting priorities from different stakeholders?', 'Behavioral & Situational', 'Make the requests visible, compare urgency, materiality, dependency, client impact, and deadline risk, propose an ordered plan, ask the accountable manager to resolve conflicts, and communicate revised expectations rather than silently missing one commitment.'),
  makeCard('ir_160', 'How would you respond if a client questioned the validity of your analysis?', 'Behavioral & Situational', 'Listen without defending the conclusion prematurely, restate the question, walk through sources, definitions, calculations, and assumptions, reproduce the result transparently, correct errors openly, and explain what new evidence would change the recommendation.'),
  makeCard('ir_162', 'How can two unevenly burning 60-second ropes measure 45 seconds?', 'Logical Puzzles', 'Light both ends of rope one and one end of rope two simultaneously. Rope one finishes in 30 seconds. At that moment light the other end of rope two; its remaining burn time is 15 seconds, giving 45 seconds total.'),
  makeCard('ir_164', 'What is your experience with data-visualization tools such as Tableau or Power BI?', 'SQL & Excel', 'Explain the business problem, data model, transformations, visual choices, controls, and validation. A strong answer describes how the dashboard changed a decision, not just which charts were built; mention refresh reliability, permissions, definitions, and performance.'),
  makeCard('ir_165', 'How do you handle repetitive tasks?', 'Behavioral & Situational', 'First understand the control objective and error risk, then standardize the steps, use templates or automation where appropriate, add validation checks, and review exceptions. Do not automate a process whose definitions or ownership are still unclear.'),
  makeCard('ir_166', 'How do you stay organized when processing large amounts of news and data every day?', 'Behavioral & Situational', 'Use a source hierarchy, recurring scan windows, a searchable log, consistent tags, saved queries, a priority score, and a daily exception list. Capture date, source, affected entity, confidence, action, and unresolved questions so information becomes reusable analysis.'),
  makeCard('ir_169', 'Would you accept a pure back-office or operations role if you were not selected for a client-facing role?', 'Behavioral & Situational', 'Show flexibility without sounding directionless. Explain how operations, data quality, monitoring, and process ownership build client impact, state the skills you would contribute, and describe a credible path to broader responsibility based on performance.'),
  makeCard('ir_170', 'What sections should a finance aptitude assessment cover, and how would you prepare?', 'Written Assessment', 'Expect quantitative ability, ratios and percentages, logical reasoning, Excel, accounting, finance and markets, current affairs, and English. Prepare timed arithmetic, accounting and ratio drills, spreadsheet shortcuts, market vocabulary, and a review method for mistakes; treat a fast-calculation test as a separate speed-and-accuracy exercise.'),
  makeCard('ir_171', 'If you are a potential candidate, would you accept this job offer at the cost of someone who has already been hired, knowing there is only one position?', 'Behavioral & Situational', 'Do not frame another candidate’s loss as a personal victory. Say you would present your fit honestly and accept a fair decision, while respecting the other person’s dignity and the employer’s process. Show ambition with integrity rather than entitlement.'),
  makeCard('ir_172', 'Contrast your views on standard operating procedures—how they are established and how you would suggest a better technique to a senior—with your views on the traditional dowry system.', 'Behavioral & Situational', 'Treat the subjects separately: an SOP is an evidence-based, reviewable control that can be improved through respectful escalation and testing; dowry is a social practice that should be evaluated through consent, dignity, equality, and legality, not normalized as a workplace analogy. The common thread is principled reasoning without disrespect.'),
  makeCard('ir_173', 'How would you answer questions about obsessive-compulsive patterns, personal routine checks, and whether they affect your efficiency?', 'Behavioral & Situational', 'Answer honestly without self-diagnosing or using a clinical label casually. Describe ordinary checking or routine behaviour only if relevant, explain the control benefit and the boundary where it could slow work, and state how you use prioritization, checklists, or support to remain effective. Do not disclose medical information beyond what you choose to share.'),
  makeCard('ir_174', 'Why did you not pursue cricket after playing at the national level, and why did you leave CA midway?', 'Behavioral & Situational', 'Give a specific, truthful transition story: what the experience taught you, why the original path changed, what you completed or learned from CA, what finance work you deliberately pursued, and why the present role is a considered choice rather than an escape from a previous path.'),
  makeCard('ir_175', 'Why do you want to switch from an accounting background to a finance background?', 'Behavioral & Situational', 'Connect accounting foundations—statement literacy, controls, accruals, and quality checks—to the finance work you want: credit, valuation, capital allocation, markets, or transaction analysis. Name the steps already taken, the technical gaps you are closing, and the evidence that the switch is intentional.'),
  makeCard('ir_176', 'Convince us why you are the best fit for Oxane Partners.', 'Behavioral & Situational', 'Build the answer from the role: rigorous financial analysis, credit and alternative-investment interest, Excel/SQL discipline, clear communication, comfort with repetitive data quality work, and client responsiveness. Support each claim with a short example and explain why Oxane’s work is the environment where those strengths create value.'),
  makeCard('ir_177', 'What is the fast-calculation test in an aptitude assessment, and how would you prepare for it?', 'Written Assessment', 'It is a timed speed-and-accuracy exercise, often focused on rapid addition and subtraction or related arithmetic. Prepare with short timed sets, estimate before calculating, keep place values aligned, avoid sacrificing accuracy for speed, and review the error pattern after each set.'),
  makeCard('ir_178', 'Walk me through building an integrated three-statement model from operating assumptions to cash and the balance-sheet check.', 'Financial Modeling', 'Start with revenue, volume, price, margins, operating expenses, working-capital days, capex, depreciation, taxes, and financing assumptions. Build the income statement, use the operating and investing schedules to construct cash flow, roll forward the balance sheet, link debt and interest through a debt schedule, and finish with a balance check plus sensitivities. Every assumption should have a causal path across all three statements.' , 'Ironsides Advisory', 'Hard'),
  makeCard('ir_179', 'If accounts receivable increases by 10, what happens across the three financial statements?', 'Financial Modeling', 'The income statement is unchanged if the increase is only a timing change. On the cash-flow statement, the increase is a use of cash in operating activities. On the balance sheet, receivables rise and cash falls by 10, so total assets still balance. If the increase reflects a credit sale, revenue and profit also rise first; isolate the timing effect from the new sale.' , 'All Firms', 'Medium'),
  makeCard('ir_180', 'How does a capital-expenditure purchase flow through the income statement, cash-flow statement, and balance sheet?', 'Financial Modeling', 'At purchase, cash decreases and PP&E increases on the balance sheet; the purchase appears as an investing cash outflow and does not immediately reduce EBIT. In later periods depreciation reduces EBIT and net income, is added back in CFO, and reduces PP&E. Test the tax shield, financing source, useful life, and any disposal proceeds.' , 'All Firms', 'Medium'),
  makeCard('ir_181', 'How would you build a debt schedule, and how do you handle circularity between interest and debt balances?', 'Financial Modeling', 'Roll forward opening debt, mandatory amortization, optional repayment, new draws, and closing debt by tranche. Calculate interest from average or beginning balances, link cash available for repayment, and use a controlled convention or a clearly documented iterative calculation when interest depends on closing debt. Add checks for minimum cash, maturity dates, cash sweep priority, and covenant headroom.' , 'Oxane Partners', 'Hard'),
  makeCard('ir_182', 'How do you forecast working capital in a three-statement model?', 'Financial Modeling', 'Forecast receivables from revenue and DSO, inventory from COGS and DIO, payables from COGS or purchases and DPO, and other operating items from the most relevant driver. Convert changes in balances into cash-flow effects, test seasonality, and reconcile the implied cash-conversion cycle against operating capacity and financing needs.' , 'Ironsides Advisory', 'Hard'),
  makeCard('ir_183', 'Explain WACC beyond the formula. Which inputs are market-based, and what common mistakes would you challenge?', 'Corporate Finance & Valuation', 'WACC blends the market-value cost of equity and after-tax cost of debt. Challenge book-value weights, stale betas, mismatched risk-free rates and cash-flow currency, using a company-wide WACC for a riskier project, an unsupported tax rate, and ignoring leases or other debt-like financing. The discount rate must match the cash flow, currency, risk, and timing.' , 'Moody\'s', 'Hard'),
  makeCard('ir_184', 'How do you unlever and relever beta when estimating the cost of equity for a target capital structure?', 'Corporate Finance & Valuation', 'Unlever each comparable beta to remove its observed financial leverage, typically using beta-u = beta-l / (1 + (1-tax rate) x debt/equity), select a peer or business beta, then relever it at the target debt/equity ratio. State the tax, peer set, capital structure, and whether debt is measured at market value.' , 'Moody\'s', 'Hard'),
  makeCard('ir_185', 'Walk me from a DCF enterprise value to equity value.', 'Corporate Finance & Valuation', 'Discount FCFF at WACC to obtain the present value of explicit cash flows and terminal value. Sum them for enterprise value, then subtract debt and debt-like claims and add excess cash and non-operating investments; adjust for minority interest or preferred stock as appropriate. Divide by diluted shares after considering options and other equity claims.' , 'Moody\'s', 'Medium'),
  makeCard('ir_186', 'How would you defend a DCF when changing WACC or terminal growth materially changes the valuation?', 'Corporate Finance & Valuation', 'Show a two-way sensitivity, explain why the inputs are uncertain, compare the implied terminal value as a percentage of EV, reconcile the implied exit multiple, and test a conservative fade from high growth to steady state. A DCF is a range of outcomes, not a precise point estimate; use trading and transaction multiples as independent cross-checks.' , 'Ironsides Advisory', 'Hard'),
  makeCard('ir_187', 'What are the most important sanity checks in a DCF and three-statement model?', 'Financial Modeling', 'Check that the balance sheet balances, cash does not go negative without a funding assumption, debt rolls correctly, margins and working-capital days are economically plausible, terminal growth is below the long-run nominal economy, implied multiples are reasonable, cash flow reconciles to changes in balance-sheet accounts, and sensitivities move in the expected direction.' , 'Ironsides Advisory', 'Hard'),
  makeCard('ir_188', 'Why might an analyst use a mid-year convention in a DCF?', 'Corporate Finance & Valuation', 'The mid-year convention assumes operating cash flows arrive throughout the year rather than all on the final day. Discounting them at the middle of each period can better match timing for recurring businesses, but the convention must be applied consistently to explicit cash flows and terminal value.' , 'Moody\'s', 'Medium'),
  makeCard('ir_189', 'Why is FCFF discounted at WACC while FCFE is discounted at the cost of equity?', 'Corporate Finance & Valuation', 'FCFF is cash available to debt and equity before financing distributions, so WACC reflects both capital providers. FCFE is the residual cash available only to equity after interest, borrowing, and principal repayment, so it is discounted at the required return on equity. Mixing the cash flow and discount rate produces a wrong value.' , 'Moody\'s', 'Medium'),
  makeCard('ir_190', 'Differentiate ABS, RMBS, and CMBS. What collateral and risk questions change across them?', 'Structured Finance & Private Credit', 'ABS is backed by non-mortgage assets such as auto loans, credit-card receivables, or consumer loans; RMBS is backed by residential mortgages; CMBS is backed by commercial mortgage loans and property cash flows. The analysis changes with collateral performance, prepayments, property or borrower concentration, servicing, structural protections, and the relevant recovery process.' , 'Moody\'s', 'Medium'),
  makeCard('ir_191', 'How are arrears, delinquencies, defaults, and losses measured in a securitization pool?', 'Structured Finance & Private Credit', 'Define each event precisely, state the denominator and ageing bucket, separate current balance from original balance, and track roll rates by vintage or seasoning. Reconcile defaults to recoveries, write-offs, severity, and cumulative net loss; compare performance with triggers, underwriting cohorts, and the base-case assumptions.' , 'Moody\'s', 'Hard'),
  makeCard('ir_192', 'What are CPR and SMM, and how do prepayments affect a securitized bond?', 'Structured Finance & Private Credit', 'CPR is an annualized conditional prepayment rate and SMM is the corresponding single-month rate. Faster prepayments can shorten weighted-average life, change reinvestment and extension risk, alter excess spread, and affect tranche cash flows; the effect depends on coupon, call or lockout features, default timing, and the waterfall.' , 'Moody\'s', 'Hard'),
  makeCard('ir_193', 'Why do weighted-average life and duration matter when analyzing a securitization tranche?', 'Structured Finance & Private Credit', 'Weighted-average life measures the timing of principal cash flows; duration measures approximate price sensitivity to rates. Both affect market and refinancing risk, but neither replaces analysis of credit spread, defaults, prepayments, extension, structural triggers, and the tranche position in the waterfall.' , 'Moody\'s', 'Hard'),
  makeCard('ir_194', 'Which structural features would you inspect in a securitization cash-flow model?', 'Structured Finance & Private Credit', 'Inspect the priority of payments, sequential or pro-rata amortization, reserve accounts, excess spread, overcollateralization, subordination, triggers, turbo provisions, servicer replacement, liquidity support, clean-up calls, interest-rate and currency hedges, and how losses and recoveries are allocated by tranche.' , 'Moody\'s', 'Hard'),
  makeCard('ir_195', 'How would you compare credit enhancement in an ABS, RMBS, and CMBS transaction?', 'Structured Finance & Private Credit', 'Compare subordination, overcollateralization, excess spread, reserve funds, guarantees, liquidity facilities, triggers, and servicing quality, then connect them to the collateral risk. Consumer pools may emphasize vintage loss and prepayment behavior; RMBS adds borrower and property characteristics; CMBS adds property cash flow, DSCR, LTV, debt yield, and concentration.' , 'Moody\'s', 'Hard'),
  makeCard('ir_196', 'Which property-level metrics matter most in a CMBS analysis?', 'Structured Finance & Private Credit', 'Focus on net operating income, DSCR, LTV, debt yield, occupancy, rent roll, lease rollover, tenant concentration, property type and location, cap rates, valuation, sponsor quality, reserves, capex, and refinanceability. Stress NOI, interest rates, vacancy, cap rates, and balloon maturity rather than relying on one ratio.' , 'Moody\'s', 'Hard'),
  makeCard('ir_197', 'What is a warehouse facility in private credit or securitization, and what would you monitor?', 'Structured Finance & Private Credit', 'A warehouse is a financing facility used to accumulate eligible assets before refinancing or securitization. Monitor borrowing-base eligibility, advance rates, haircuts, concentration limits, collateral marks, margin calls, funding cost, facility covenants, liquidity, aging, hedges, and the take-out or term-out plan.' , 'Oxane Partners', 'Hard'),
  makeCard('ir_198', 'How would you monitor a private-credit portfolio after closing?', 'Credit & Underwriting', 'Create a repeatable cadence for financial statements, covenant tests, liquidity, collateral, payments, amendments, ratings, news, industry stress, and maturity walls. Track exceptions and covenant headroom, compare actuals with the underwriting case, escalate early-warning signals, and preserve an auditable history of decisions.' , 'Oxane Partners', 'Medium'),
  makeCard('ir_199', 'How would you build and audit a loan-amortization model in Excel?', 'Financial Modeling', 'Set up opening principal, drawdowns, scheduled amortization, optional prepayments, interest-rate assumptions, day-count convention, fees, and closing balance. Use separate input, calculation, output, and check sections; reconcile total principal and interest to the agreement; test prepayment, default, and maturity cases.' , 'Oxane Partners', 'Hard'),
  makeCard('ir_200', 'Write a SQL approach using a CTE or window function to return the latest covenant test for each facility.', 'SQL & Excel', 'Partition tests by facility, order by reporting date descending, and use ROW_NUMBER to retain the latest approved record. Join it to facility and borrower dimensions, filter active facilities, and validate duplicates, missing dates, and row counts against the source report.' , 'Oxane Partners', 'Hard'),
  makeCard('ir_201', 'What does a 13-week cash-flow forecast reveal that annual financial statements may miss?', 'Financial Due Diligence', 'It exposes near-term timing risk: weekly receipts, payroll, taxes, supplier payments, debt service, minimum cash, revolver availability, and liquidity shortfalls. Build it from realistic collections and disbursement schedules, reconcile to bank data, and stress delays, lower sales, and covenant or borrowing-base constraints.' , 'Ironsides Advisory', 'Hard'),
  makeCard('ir_202', 'How would you present a Quality of Earnings bridge to a transaction team?', 'Financial Due Diligence', 'Start with reported EBITDA, isolate non-recurring, out-of-period, non-cash, owner-related, run-rate, and pro forma adjustments, document evidence for each item, and arrive at a defensible normalized EBITDA range. Link adjustments to cash, working capital, taxes, debt-like items, and the purchase-price mechanism.' , 'Ironsides Advisory', 'Hard'),
  makeCard('ir_203', 'How do you set a normalized working-capital peg for a purchase-price mechanism?', 'Financial Due Diligence', 'Define operating NWC, exclude cash and debt-like items consistently, analyze monthly history and seasonality, remove unusual events, align the peg with the target level needed to operate normally, and test whether the closing balance has been managed to the target. Explain the effect on equity value for an over- or under-delivery.' , 'Ironsides Advisory', 'Hard'),
  makeCard('ir_204', 'How would you distinguish a debt-like item from normal working capital in transaction diligence?', 'Financial Due Diligence', 'Ask whether the item is a recurring operating balance required to deliver normal revenue or a financing-like obligation that transfers value or requires a post-close cash payment. Examine contractual terms, historical treatment, cash settlement, accounting classification, and double-counting between debt, NWC, and the purchase-price adjustment.' , 'Ironsides Advisory', 'Hard'),
  makeCard('ir_205', 'How do purchase-price allocation and impairment testing connect after an acquisition?', 'M&A Tax & Structuring', 'Allocate consideration to identifiable tangible and intangible assets and liabilities at fair value, with residual value generally assigned to goodwill. Document valuation methods and useful lives, then test finite-lived assets and goodwill for impairment under the applicable accounting framework. Challenge forecasts, discount rates, attrition, royalty rates, and market evidence.' , 'Ironsides Advisory', 'Hard'),
  makeCard('ir_206', 'What tax questions would you ask when comparing an asset deal with a stock deal?', 'M&A Tax & Structuring', 'Compare tax basis step-up, depreciation or amortization, transfer taxes, inherited liabilities, tax attributes, withholding, legal entity continuity, indemnities, and the seller and buyer tax positions. Model cash taxes and timing rather than assuming the headline tax rate captures the value.' , 'Ironsides Advisory', 'Hard'),
  makeCard('ir_207', 'How would you write a concise credit-rating rationale or short credit note from a large data pack?', 'Credit & Underwriting', 'Lead with the decision and rating-relevant thesis, then cover business profile, financial performance, liquidity, leverage, coverage, event risk, structural protections, key sensitivities, and mitigants. Separate facts, estimates, and judgment; cite dates and sources; and finish with clear monitoring triggers.' , 'Moody\'s', 'Medium'),
  makeCard('ir_208', 'How do rating migration and early-warning monitoring differ from a one-time credit approval?', 'Credit & Underwriting', 'Approval asks whether the risk is acceptable at origination; monitoring asks whether the risk has changed and whether action is needed. Track operating results, leverage, liquidity, covenant headroom, market signals, management changes, collateral, maturity and refinancing risk, then update the base and downside cases as evidence arrives.' , 'Moody\'s', 'Medium'),
  makeCard('ir_209', 'What types of debt are included in Enterprise Value, and why are debt and excess cash adjusted?', 'Corporate Finance & Valuation', 'Include funded borrowings such as revolvers, term loans, bonds, current maturities, finance leases, and other debt-like claims when they represent a financing obligation. Add debt because it is a claim on the operating business and subtract excess cash because an acquirer receives it; keep operating cash needed to run the business.' , 'Moody\'s', 'Medium'),
  makeCard('ir_210', 'What is NPV? What is IRR? What is the formula for calculating IRR?', 'Corporate Finance & Valuation', 'NPV is the present value of project cash inflows and outflows discounted at the appropriate required return, including the initial investment. IRR is the rate that makes NPV equal to zero: 0 = sum of CFt divided by (1 + IRR)^t. Use NPV as the primary value-creation test and explain scale, timing, and multiple-IRR limitations.' , 'Moody\'s', 'Medium'),
  makeCard('ir_211', 'What is EBITDA, and as an investor would you consider EBITDA or Net Profit for judging a potential investment?', 'Corporate Finance & Valuation', 'EBITDA is EBIT plus depreciation and amortization and is a pre-interest, pre-tax operating measure, not cash flow. Use EBITDA to compare operations and debt capacity, but reconcile to net profit, taxes, capex, working capital, and cash before deciding whether the investment creates value or can service debt.' , 'Moody\'s', 'Medium'),
  makeCard('ir_212', 'Write SQL queries involving joins, subqueries, and data manipulation.', 'SQL & Excel', 'Explain the keys and grain first, then write a clear SELECT with the appropriate INNER or LEFT JOIN, use a CTE or subquery for staged logic, and apply INSERT, UPDATE, or DELETE only with a transaction, selective predicates, row-count checks, and rollback or review controls.' , 'Moody\'s', 'Medium'),
];

export const interviewReadyRelatedExpansion = [
  { id: 'ir_r011', question: 'How do SMA-0, SMA-1, SMA-2, and NPA differ in a credit-monitoring dashboard?', category: 'Interview Ready', tag: 'related', subcategory: 'Credit & Underwriting', firm: "Moody's", difficulty: 'Medium', answer: 'They form an escalating early-warning and impairment sequence based on overdue or out-of-order behaviour. The exact buckets depend on the applicable RBI framework; the analyst should monitor ageing, drawing-power excess, cash credits, and cure behaviour rather than treating SMA as an accounting label alone.', relatedIds: ['ir_057', 'ir_029', 'ir_027'] },
  { id: 'ir_r012', question: 'How do mortgage, hypothecation, pledge, and lien differ as security interests?', category: 'Interview Ready', tag: 'related', subcategory: 'Structured Finance & Private Credit', firm: 'Oxane Partners', difficulty: 'Medium', answer: 'Mortgage secures immovable property; hypothecation secures movable assets without transferring possession; pledge secures movable goods with possession or control delivered to the pledgee; a lien is a right to retain property until an obligation is paid. Enforceability depends on documents, perfection, priority, and possession or control.', relatedIds: ['ir_058', 'ir_059', 'ir_060'] },
  { id: 'ir_r013', question: 'How do projected balance sheets and drawing power work together in working-capital underwriting?', category: 'Interview Ready', tag: 'related', subcategory: 'Credit & Underwriting', firm: "Moody's", difficulty: 'Medium', answer: 'Projected statements forecast the operating cycle and peak funding need; drawing power converts eligible receivables and inventory into a collateral-based borrowing limit after margins and exclusions. Compare both so the facility is supported by cash generation and realizable collateral.', relatedIds: ['ir_107', 'ir_114', 'ir_056'] },
  { id: 'ir_r014', question: 'How do you distinguish transaction risk, business risk, and financial risk in a credit memo?', category: 'Interview Ready', tag: 'related', subcategory: 'Credit & Underwriting', firm: "Moody's", difficulty: 'Medium', answer: 'Business risk concerns demand, competition, margins, and operating resilience; financial risk concerns leverage, liquidity, coverage, and cash conversion; transaction risk concerns whether tenor, amortization, covenants, security, guarantees, and documentation fit the identified risks.', relatedIds: ['ir_111', 'ir_027', 'ir_060'] },
  { id: 'ir_r015', question: 'How do you reconcile EBITDA, EBIT, net income, CFO, FCFF, and FCFE in one valuation answer?', category: 'Interview Ready', tag: 'related', subcategory: 'Corporate Finance & Valuation', firm: "Moody's", difficulty: 'Hard', answer: 'EBITDA adds back D&A; EBIT includes D&A before interest and tax; net income is after interest and tax; CFO adjusts net income for non-cash items and working capital; FCFF is pre-financing cash for debt and equity; FCFE is residual cash for equity after financing flows. Match each measure to its denominator, discount rate, and valuation objective.', relatedIds: ['ir_007', 'ir_125', 'ir_126'] },
  { id: 'ir_r016', question: 'When can NPV and IRR disagree, and how should an analyst resolve the conflict?', category: 'Interview Ready', tag: 'related', subcategory: 'Corporate Finance & Valuation', firm: "Moody's", difficulty: 'Medium', answer: 'They can disagree when projects differ in scale, timing, life, or reinvestment assumptions, or when cash flows change sign more than once. Prefer NPV at the appropriate risk-adjusted discount rate for value creation, then explain IRR, incremental cash flows, and strategic constraints.', relatedIds: ['ir_016', 'ir_020', 'ir_124'] },
  { id: 'ir_r017', question: 'How does a recession transmit from sales growth to debt-service capacity?', category: 'Interview Ready', tag: 'related', subcategory: 'Credit & Underwriting', firm: "Moody's", difficulty: 'Medium', answer: 'Lower volume or pricing reduces gross profit; operating leverage compresses EBITDA; receivables and inventory may consume cash; fixed interest and principal remain; leverage rises and coverage falls. Stress the full cash bridge rather than applying a single revenue haircut.', relatedIds: ['ir_112', 'ir_004', 'ir_006'] },
  { id: 'ir_r018', question: 'What controls make a SQL-based credit report auditable?', category: 'Interview Ready', tag: 'related', subcategory: 'SQL & Excel', firm: 'Oxane Partners', difficulty: 'Medium', answer: 'Use versioned SQL, documented definitions, stable keys, source-to-output lineage, row-count and total reconciliations, exception reports, controlled deployments, test fixtures, access controls, and an immutable run log with input dates and parameters.', relatedIds: ['ir_145', 'ir_146', 'ir_154'] },
  { id: 'ir_r019', question: 'How do you combine Excel flexibility with model-control discipline?', category: 'Interview Ready', tag: 'related', subcategory: 'SQL & Excel', firm: 'Oxane Partners', difficulty: 'Medium', answer: 'Separate inputs, calculations, outputs, and checks; avoid hard-coded numbers; use named ranges and consistent conventions; protect formulas; reconcile totals; version the workbook; and document assumptions and refresh steps. Automation should improve repeatability, not hide logic.', relatedIds: ['ir_149', 'ir_154', 'ir_155'] },
  { id: 'ir_r020', question: 'What evidence would you seek before treating a management or technology warning as credit deterioration?', category: 'Interview Ready', tag: 'related', subcategory: 'Credit & Underwriting', firm: "Moody's", difficulty: 'Medium', answer: 'Look for changes in customers, margins, churn, backlog, capex, obsolete inventory, cyber incidents, control failures, key-person dependence, refinancing access, covenant headroom, and cash-flow forecasts. Convert the qualitative warning into a measurable downside case.', relatedIds: ['ir_117', 'ir_121', 'ir_113'] },
  { id: 'ir_r021', question: 'What are the three most important links in an integrated three-statement model?', category: 'Interview Ready', tag: 'related', subcategory: 'Financial Modeling', firm: 'Ironsides Advisory', difficulty: 'Medium', answer: 'Net income flows into retained earnings and begins cash flow from operations; non-cash and working-capital adjustments reconcile earnings to cash; capex and financing schedules update PP&E, debt, interest, and cash. The balance sheet check confirms the links are complete.', relatedIds: ['ir_178', 'ir_179', 'ir_180'] },
  { id: 'ir_r022', question: 'What is the difference between WACC, cost of equity, and a project hurdle rate?', category: 'Interview Ready', tag: 'related', subcategory: 'Corporate Finance & Valuation', firm: "Moody's", difficulty: 'Medium', answer: 'WACC is a blended required return for operating cash flows available to debt and equity; cost of equity is the return required only by shareholders; a project hurdle rate should reflect the risk and financing of that project, not automatically the company-wide WACC.', relatedIds: ['ir_017', 'ir_183', 'ir_189'] },
  { id: 'ir_r023', question: 'How does a DCF sensitivity table improve an interview answer?', category: 'Interview Ready', tag: 'related', subcategory: 'Corporate Finance & Valuation', firm: "Moody's", difficulty: 'Medium', answer: 'It shows how value changes when key uncertain drivers such as WACC, terminal growth, margins, or revenue change. Explain the central case, range, economic reason for the movement, and whether the implied multiples remain credible.', relatedIds: ['ir_186', 'ir_187', 'ir_188'] },
  { id: 'ir_r024', question: 'How do ABS, RMBS, and CMBS differ in the risks an analyst must monitor?', category: 'Interview Ready', tag: 'related', subcategory: 'Structured Finance & Private Credit', firm: "Moody's", difficulty: 'Hard', answer: 'ABS focuses on consumer or commercial receivable performance and servicing; RMBS adds mortgage borrower, property, and prepayment behavior; CMBS adds property cash flow, lease rollover, valuation, concentration, and balloon-refinancing risk. All require waterfall and enhancement analysis.', relatedIds: ['ir_190', 'ir_195', 'ir_196'] },
  { id: 'ir_r025', question: 'How do CPR, arrears, WAL, and tranche subordination interact?', category: 'Interview Ready', tag: 'related', subcategory: 'Structured Finance & Private Credit', firm: "Moody's", difficulty: 'Hard', answer: 'Arrears and defaults affect loss timing and severity; CPR changes principal timing; WAL summarizes when principal is returned; and subordination determines which tranche absorbs losses first. A robust analysis models them together rather than treating each metric independently.', relatedIds: ['ir_191', 'ir_192', 'ir_193'] },
  { id: 'ir_r026', question: 'What distinguishes a warehouse facility from the final securitization?', category: 'Interview Ready', tag: 'related', subcategory: 'Structured Finance & Private Credit', firm: 'Oxane Partners', difficulty: 'Medium', answer: 'A warehouse is interim financing used while assets are accumulated and monitored; the final securitization term-outs or sells funded tranches to investors. Warehouse risk includes advance rates, eligibility, margin calls, funding liquidity, and take-out execution.', relatedIds: ['ir_197', 'ir_028', 'ir_023'] },
  { id: 'ir_r027', question: 'How would you connect a QofE adjustment to valuation and credit risk?', category: 'Interview Ready', tag: 'related', subcategory: 'Financial Due Diligence', firm: 'Ironsides Advisory', difficulty: 'Hard', answer: 'First prove whether the adjustment is recurring, cash, and sustainable; then update normalized EBITDA, leverage, taxes, working capital, debt capacity, DCF, and purchase price. A higher EBITDA without cash support should not automatically improve credit quality.', relatedIds: ['ir_202', 'ir_204', 'ir_038'] },
  { id: 'ir_r028', question: 'What is the difference between a 13-week cash forecast and a three-statement forecast?', category: 'Interview Ready', tag: 'related', subcategory: 'Financial Due Diligence', firm: 'Ironsides Advisory', difficulty: 'Medium', answer: 'A 13-week forecast is a near-term liquidity and timing tool built around actual receipts and disbursements; a three-statement forecast explains profitability, investment, financing, and balance-sheet evolution over longer periods. Use both when solvency and immediate liquidity can diverge.', relatedIds: ['ir_201', 'ir_178', 'ir_182'] },
  { id: 'ir_r029', question: 'What SQL and Excel controls prevent a portfolio-monitoring report from becoming a black box?', category: 'Interview Ready', tag: 'related', subcategory: 'SQL & Excel', firm: 'Oxane Partners', difficulty: 'Medium', answer: 'Use stable keys, documented definitions, versioned queries, controlled inputs, formula separation, source-to-output lineage, reconciliation totals, exception logs, review sign-offs, and repeatable test cases. Every manual override should be visible and explainable.', relatedIds: ['ir_199', 'ir_200', 'ir_r018'] },
  { id: 'ir_r030', question: 'What makes a credit note decision-useful rather than merely descriptive?', category: 'Interview Ready', tag: 'related', subcategory: 'Credit & Underwriting', firm: "Moody's", difficulty: 'Medium', answer: 'It links business and financial facts to repayment capacity, downside scenarios, structural protection, and a clear recommendation. It distinguishes evidence from assumptions and states what monitoring event would change the conclusion.', relatedIds: ['ir_207', 'ir_208', 'ir_r014'] },
];

export const interviewReadyGeneratedExpansion = [
  { id: 'ir_g011', question: 'A borrower’s receivables days rise by 15 days while inventory days fall by 5 days. What is the net working-capital cash effect?', category: 'Interview Ready', tag: 'gen', subcategory: 'Credit & Underwriting', firm: 'Oxane Partners', difficulty: 'Medium', answer: 'Receivables rising by 15 days consumes cash; inventory falling by 5 days releases cash. Net effect is a 10-day increase in operating working-capital investment, before considering margins, seasonality, and payables.', relatedIds: ['ir_056', 'ir_112', 'ir_r017'] },
  { id: 'ir_g012', question: 'A factory is offered as collateral, but the lender cannot perfect the mortgage. What risks remain?', category: 'Interview Ready', tag: 'gen', subcategory: 'Structured Finance & Private Credit', firm: 'Oxane Partners', difficulty: 'Hard', answer: 'The lender may lose priority, face enforceability or title defects, encounter prior charges, or be unable to realize value efficiently. Verify title, registration, valuation, insurance, possession, statutory dues, existing encumbrances, and the enforcement route.', relatedIds: ['ir_058', 'ir_111', 'ir_r012'] },
  { id: 'ir_g013', question: 'A company reports 1.8x DSCR using EBITDA but 0.9x using CFO. What would you investigate?', category: 'Interview Ready', tag: 'gen', subcategory: 'Credit & Underwriting', firm: "Moody's", difficulty: 'Hard', answer: 'Investigate receivables and inventory investment, taxes, cash interest, restructuring costs, capex, seasonality, one-time EBITDA adjustments, and the precise debt-service definition. The gap may show EBITDA is not converting into cash.', relatedIds: ['ir_006', 'ir_007', 'ir_146'] },
  { id: 'ir_g014', question: 'A project has positive NPV but an IRR below the company’s headline hurdle rate. How would you present the decision?', category: 'Interview Ready', tag: 'gen', subcategory: 'Corporate Finance & Valuation', firm: "Moody's", difficulty: 'Medium', answer: 'Validate the project cash flows, scale, timing, risk-adjusted discount rate, and terminal assumptions. If NPV is positive at the correct project WACC, it creates value even if a headline IRR comparison is misleading; explain the reason rather than choosing a metric mechanically.', relatedIds: ['ir_124', 'ir_r016', 'ir_130'] },
  { id: 'ir_g015', question: 'How would you build a simple SQL query to find borrowers whose covenant headroom fell below 10%?', category: 'Interview Ready', tag: 'gen', subcategory: 'SQL & Excel', firm: 'Oxane Partners', difficulty: 'Medium', answer: 'Join borrowers, facilities, covenant tests, and reporting periods on stable keys; calculate headroom as the permitted threshold minus the reported metric or the appropriate ratio; filter headroom below 10%; and validate the result against the latest approved covenant report.', relatedIds: ['ir_027', 'ir_145', 'ir_154'] },
  { id: 'ir_g016', question: 'A short seller alleges fraud, but regulators have not concluded their review. How should a credit memo handle it?', category: 'Interview Ready', tag: 'gen', subcategory: 'Structured Finance & Private Credit', firm: "Moody's", difficulty: 'Hard', answer: 'Label allegations as allegations, cite the primary public materials, summarize the issuer response and verified facts, identify what remains unknown, and stress liquidity, governance, related parties, collateral, refinancing, and contagion. Do not convert a headline into a default probability without evidence.', relatedIds: ['ir_131', 'ir_078', 'ir_r020'] },
  { id: 'ir_g017', question: 'An equity analyst recommends a leveraged company while a credit analyst recommends avoiding its bonds. Can both be right?', category: 'Interview Ready', tag: 'gen', subcategory: 'Credit & Underwriting', firm: "Moody's", difficulty: 'Medium', answer: 'Yes. Equity may value upside from growth or deleveraging while credit focuses on default probability, recovery, covenant protection, and refinancing risk. Different claims, time horizons, cash-flow priorities, and payoff asymmetries can produce different conclusions.', relatedIds: ['ir_g008', 'ir_136', 'ir_138'] },
  { id: 'ir_g018', question: 'How would you test whether a 20% revenue forecast is a meaningful operating assumption or a plug?', category: 'Interview Ready', tag: 'gen', subcategory: 'Corporate Finance & Valuation', firm: 'Ironsides Advisory', difficulty: 'Medium', answer: 'Bridge growth by volume, price, mix, customers, capacity, pipeline conversion, churn, and market share; compare it with history and external evidence; check working capital and capex implications; and run downside cases that preserve causal links across the statements.', relatedIds: ['ir_113', 'ir_033', 'ir_154'] },
  { id: 'ir_g019', question: 'What would you do if a senior reviewer asks you to remove a material model exception before sending the report?', category: 'Interview Ready', tag: 'gen', subcategory: 'Behavioral & Situational', firm: 'Ironsides Advisory', difficulty: 'Medium', answer: 'Clarify the reason, show the evidence and impact, propose a documented correction or explicit disclosure, escalate through the review chain if needed, and do not remove a material exception without an approved basis. Protect the client and the audit trail.', relatedIds: ['ir_157', 'ir_078', 'ir_160'] },
  { id: 'ir_g020', question: 'How would you explain a bond’s duration to a non-finance stakeholder using one risk sentence?', category: 'Interview Ready', tag: 'gen', subcategory: 'Fixed Income & Derivatives', firm: 'Oxane Partners', difficulty: 'Easy', answer: 'Duration is an approximate measure of how sensitive a bond’s price is to a change in interest rates: a five-year duration implies roughly a 5% price fall for a 1% parallel yield rise, before convexity and credit-spread effects.', relatedIds: ['ir_030', 'ir_132', 'ir_136'] },
  { id: 'ir_g021', question: 'Revenue is flat, receivables rise, inventory rises, and debt is unchanged. What would you say about cash and credit quality?', category: 'Interview Ready', tag: 'gen', subcategory: 'Financial Modeling', firm: 'Moody\'s', difficulty: 'Hard', answer: 'Cash from operations is likely deteriorating because working capital is consuming cash without revenue growth. Investigate customer collections, inventory obsolescence, channel stuffing, supplier terms, liquidity headroom, and whether the borrower needs more debt to fund the same sales.', relatedIds: ['ir_179', 'ir_182', 'ir_208'] },
  { id: 'ir_g022', question: 'A DCF implies an EV/EBITDA exit multiple far above peers. What would you test?', category: 'Interview Ready', tag: 'gen', subcategory: 'Corporate Finance & Valuation', firm: "Moody's", difficulty: 'Medium', answer: 'Test terminal growth, WACC, normalized margins, reinvestment, cyclicality, and whether the forecast year is unusually depressed. Recalculate using a normalized exit year and compare with trading and transaction evidence before accepting the valuation.', relatedIds: ['ir_185', 'ir_186', 'ir_187'] },
  { id: 'ir_g023', question: 'A securitization has strong excess spread but rapidly rising arrears. What could happen next?', category: 'Interview Ready', tag: 'gen', subcategory: 'Structured Finance & Private Credit', firm: "Moody's", difficulty: 'Hard', answer: 'Excess spread may absorb early losses, but rising arrears can become defaults and reduce future spread. Test timing, recoveries, triggers, reserve funding, servicer behavior, and whether the waterfall switches from pro-rata to sequential amortization or diverts cash to protect senior notes.', relatedIds: ['ir_191', 'ir_194', 'ir_195'] },
  { id: 'ir_g024', question: 'A CMBS loan has a low LTV but weak DSCR. Is it safe?', category: 'Interview Ready', tag: 'gen', subcategory: 'Structured Finance & Private Credit', firm: "Moody's", difficulty: 'Hard', answer: 'Not necessarily. Low LTV provides value protection, but weak DSCR signals inadequate current property cash flow and possible refinancing stress. Check NOI quality, occupancy, lease rollover, cap-rate sensitivity, debt yield, reserves, sponsor support, and balloon maturity.', relatedIds: ['ir_196', 'ir_030', 'ir_193'] },
  { id: 'ir_g025', question: 'A warehouse borrowing base falls below drawn debt. How would you respond?', category: 'Interview Ready', tag: 'gen', subcategory: 'Structured Finance & Private Credit', firm: 'Oxane Partners', difficulty: 'Hard', answer: 'Quantify the collateral shortfall, identify ineligible assets or valuation changes, test margin-call and cure terms, restrict further draws if required, seek repayment or additional collateral, and update the take-out plan. Escalate before the facility breaches a hard covenant.', relatedIds: ['ir_197', 'ir_198', 'ir_027'] },
  { id: 'ir_g026', question: 'A three-statement model balances, but cash is negative and debt never increases. What is wrong?', category: 'Interview Ready', tag: 'gen', subcategory: 'Financial Modeling', firm: 'Ironsides Advisory', difficulty: 'Medium', answer: 'The model may balance mechanically while omitting a funding source, allowing an impossible cash balance, or failing to link the debt schedule and minimum-cash sweep. Add explicit revolver draws or an operating constraint, then test the balance check and cash waterfall again.', relatedIds: ['ir_178', 'ir_181', 'ir_187'] },
  { id: 'ir_g027', question: 'A QofE adjustment increases EBITDA but also increases working-capital needs. How should valuation change?', category: 'Interview Ready', tag: 'gen', subcategory: 'Financial Due Diligence', firm: 'Ironsides Advisory', difficulty: 'Hard', answer: 'Do not capitalize the EBITDA increase without modeling the cash investment needed to support it. Update FCFF, NWC, taxes, capex, leverage, and the purchase-price bridge; the value impact depends on whether the earnings are sustainable and cash generative.', relatedIds: ['ir_202', 'ir_203', 'ir_204'] },
  { id: 'ir_g028', question: 'A SQL report shows two latest covenant tests for one facility. How would you debug it?', category: 'Interview Ready', tag: 'gen', subcategory: 'SQL & Excel', firm: 'Oxane Partners', difficulty: 'Medium', answer: 'Check duplicate source rows, reporting-period definitions, approval status, effective timestamps, joins that multiply records, and the window-function ordering. Define the business rule for latest, isolate the duplicate with a diagnostic query, and reconcile the final row to the approved source report.', relatedIds: ['ir_200', 'ir_146', 'ir_r029'] },
  { id: 'ir_g029', question: 'A borrower misses a covenant but remains current on interest. What is your first credit response?', category: 'Interview Ready', tag: 'gen', subcategory: 'Credit & Underwriting', firm: "Moody's", difficulty: 'Medium', answer: 'Confirm the covenant definition and cure rights, quantify the breach and headroom trend, identify the operating cause, review liquidity and maturities, and assess whether the breach is an early warning or a temporary technical event. Escalate under the agreement and update the downside case.', relatedIds: ['ir_027', 'ir_198', 'ir_208'] },
  { id: 'ir_g030', question: 'How would you explain a tax basis step-up to a non-tax interviewer?', category: 'Interview Ready', tag: 'gen', subcategory: 'M&A Tax & Structuring', firm: 'Ironsides Advisory', difficulty: 'Easy', answer: 'The buyer gets a higher tax basis in acquired assets, which may create future depreciation or amortization deductions and lower cash taxes. Compare that benefit with purchase price, transaction taxes, legal structure, and the seller’s tax cost; model timing rather than treating it as free value.', relatedIds: ['ir_205', 'ir_206', 'ir_043'] },
];
